import { BedrockAgentRuntimeClient, InvokeAgentCommand } from '@aws-sdk/client-bedrock-agent-runtime';
import { Vex } from '@vex/sdk';

const bedrock = new BedrockAgentRuntimeClient({ region: 'us-east-1' });
const vex = new Vex({ apiKey: process.env.VEX_API_KEY });

const agentPolicy = vex.policy('bedrock-enterprise-saas', {
  rules: [
    'response.sessionState.promptSession.sessionAttributes.tenantId === input.sessionAttributes.tenantId',
    'response.trace?.retrievedReferences?.length > 0 || response.completion !== "No relevant documents found"',
    '!response.outputText.match(/(\\b(?:SSN|credit card|passport)\\b)/gi)',
    'response.statusCode === "SUCCESS"'
  ]
});

async function invokeVerifiedAgent(agentId: string, sessionId: string, input: string, tenantId: string) {
  const command = new InvokeAgentCommand({
    agentId,
    agentAliasId: 'latest',
    sessionId,
    inputText: input,
    sessionState: {
      sessionAttributes: { tenantId }
    }
  });

  const response = await bedrock.send(command);

  const stream = response.completion();
  const fullResponse = await streamToString(stream);

  const verified = await agentPolicy.verify({ input, response: fullResponse });
  if (!verified.passes) {
    throw new Error(`Vex verification failed: ${JSON.stringify(verified.failures)}`);
  }

  return fullResponse;
}

function streamToString(stream: any): Promise<string> {
  return new Promise((resolve, reject) => {
    let result = '';
    stream.on('data', (chunk: any) => result += chunk.chunk?.bytes ? new TextDecoder().decode(chunk.chunk.bytes) : '');
    stream.on('end', () => resolve(result));
    stream.on('error', reject);
  });
}

import boto3
import vex
import json

class BedrockAgentGuard:
    def __init__(self, agent_id, vex_policy_id):
        self.bedrock = boto3.client('bedrock-agent-runtime')
        self.vex_policy = vex.load_policy(vex_policy_id)
        self.session_history = {}

    def invoke_with_guardrails(self, session_id, input_text, tenant_config):
        # Verify data residency
        if tenant_config['region'] != 'us-east-1':
            raise ValueError('Data residency violation')

        response = self.bedrock.invoke_agent(
            agentId=self.agent_id,
            sessionId=session_id,
            inputText=input_text,
            sessionState={
                'sessionAttributes': {
                    'tenantId': tenant_config['tenantId'],
                    'sessionTurn': self.session_history.get(session_id, 0) + 1
                }
            }
        )

        # Vex verification with session continuity check
        context = {
            'input': input_text,
            'response': response,
            'prior_turn': self.session_history.get(session_id, {}),
            'tenant': tenant_config
        }

        verification = self.vex_policy.verify(context)
        if not verification.passed:
            # Audit log failure
            self.log_audit_failure(session_id, verification.failures)
            raise ValueError('Compliance verification failed')

        self.session_history[session_id] = {
            'turn': context['sessionState']['sessionAttributes']['sessionTurn'],
            'tenant': tenant_config['tenantId']
        }

        return response

    def log_audit_failure(self, session_id, failures):
        print(f"AUDIT LOG: Session {session_id} failed: {json.dumps(failures)}")
